using System.Collections.Generic;
using UnityEngine;

/// <summary>Como este evento é disparado pelo player.</summary>
public enum NpcInteractionType
{
    /// <summary>Dispara automaticamente quando o player entra no alcance (sem precisar de input).</summary>
    Auto,

    /// <summary>Dispara quando o player toca no NPC (collider/trigger).</summary>
    Touch,

    /// <summary>Dispara quando o player está no alcance e prime o botão de interação.</summary>
    Button
}

/// <summary>
/// Um evento configurável de NPC: um conjunto de condições que, quando todas
/// verdadeiras, permitem disparar uma sequência de ações.
///
/// A lista de eventos de um NpcController é avaliada por ordem de "priority"
/// (maior primeiro); o primeiro evento activo, no alcance certo (se aplicável)
/// e cujas condições sejam todas verdadeiras é o que dispara.
/// </summary>
[System.Serializable]
public class NpcEvent
{
    [Tooltip("Identificador único deste evento (usado por outros eventos/escolhas para activar/desactivar este).")]
    public string eventId;

    [Tooltip("Nome só para organização no Inspector.")]
    public string label = "Novo Evento";

    [Tooltip("Eventos com prioridade mais alta são avaliados primeiro.")]
    public int priority = 0;

    [Tooltip("Como este evento é disparado pelo player.")]
    public NpcInteractionType interactionType = NpcInteractionType.Button;

    [Tooltip("Distância máxima do player para Auto/Button. Se <= 0, usa o 'Default Interaction Range' do NpcController.")]
    public float interactionRange = 0f;

    [Tooltip("Se este evento começa activo (pode disparar) ao iniciar a cena.")]
    public bool startActive = true;

    [Tooltip("Sprite do NPC enquanto este evento está activo (opcional).")]
    public Sprite overrideSprite;

    [Tooltip("Condições que têm de ser todas verdadeiras para o evento poder disparar (lista vazia = sempre verdadeiro).")]
    [SerializeReference]
    public List<NpcCondition> conditions = new List<NpcCondition>();

    [Tooltip("Ações executadas em sequência quando o evento dispara.")]
    [SerializeReference]
    public List<NpcAction> actions = new List<NpcAction>();

    [Tooltip("Desactiva este evento (deixa de poder disparar) depois de correr.")]
    public bool deactivateOnComplete = false;

    [Tooltip("ID de outro evento a activar quando este terminar (vazio = nenhum).")]
    public string activateEventIdOnComplete;

    /// <summary>Estado em runtime: se este evento pode actualmente ser avaliado/disparado.</summary>
    [HideInInspector]
    public bool isActive = true;
}
